INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00005', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '市場上的生產者與消費者會隨著產品價格的上漲或下跌，不斷地調整其生產或消費行為，最後會達到市場 均衡。下列針對此市場均衡的相關敘述，何者正確？', '["無謂損失等於零", "生產者剩餘達到最小值", "社會總剩餘等於消費者剩餘", "社會福利等於社會總效益加社會總成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00006', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '假設政府發出公告：「近來國內經濟發展穩定，經政府核定列冊之低收入戶及中低收入戶，政府會加發生 活補助，低收入戶每人每月發給750元，中低收入戶每人每月發給500元」。前述政策內容，最符合下列 何項理論的內涵？', '["符合多數人福祉的效益主義觀點", "照顧弱勢者權益的社會平等觀點", "追求群體共同利益的社群主義觀點", "透過私利實現公益的自由主義觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00007', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '有學者研究指出臺灣高等教育「反向重分配」的事實：社會地位越高的家庭，相對於較低的家庭，其子女反 而能得到較多的政府教育資源。從經濟資本與文化資本兩個概念來觀察，下列敘述何者最能符合題文的描述？', '["父母職業聲望對子女社會地位影響力擴大", "親子間社會地位的世代流動距離得以擴大", "父母的成就動機對子女社會地位流動的影響得以擴大", "父母的教育程度高低對子女社會地位流動的影響變小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00008', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '有媒體報導，在某國的益智節目中，參賽者被問了一道問題：「在臺灣，人們說食物 QQ 的，是什麼意 思？」答案選項分別是：A.形容媽媽的味道；B.形容食物有嚼勁；C.指食物含有酒精。兩位參賽者討論、 思考後，最終決定選擇C，因而錯失繼續挑戰百萬獎金的機會。而在同一報導中，臺灣網友表示，「這就 內建在腦袋中，就QQ的，要解釋什麼？」對於上述所反映的文化現象，下列敘述何者最為正確？', '["參賽者係身處在該社會環境下的不利處境而無法正確回答", "網友認為「QQ」實無須解釋，係反映我族中心主義的優越態度", "「QQ」作為一種符號，在不同文化下呈現不同的認知與使用意義", "參賽題目設計者認為「QQ」在不同文化下應有著相同的意義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00009', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '不少研究發現，在異性戀伴侶中，大部分家務和照顧孩子的工作，是女方責任。根據勞動部統計，2020年 育嬰留職停薪初次核付件數，男女比例還是以女性居多，超過8成。綜上所述，從家務勞動的角度推論， 下列敘述何者為正確？', '["家務勞動的主力是女性，發生於私領域不涉及社會生活", "為肯定家務勞動價值，民法規定夫妻要協議自由處分金", "家務勞動分工與育嬰的現象與職場上男女薪資差異有關", "依勞動參與率計算公式，家務勞動者被歸類為非勞動力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00010', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）是一個多邊關係的自由貿易協定，成員國人口規模將近 5 億，總 GDP占全球13.1%，貿易值占我國貿易總值超過24%。2021年9月中國提出申請加入CPTPP書面信函， 位於亞太地區的我國亦延續加入世界貿易組織的模式遞交入會申請函。根據上述，下列何者正確？', '["該組織由美國主導，為印太戰略布局與RCEP互別苗頭", "中國申請加入，意在取代美國於該組織中的領導地位", "成為該組織成員不以國家為要件，經濟體亦可申請加入", "我國與中國皆申請加入該組織，顯見中國放棄一中原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00011', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '某公營電視台播出時，螢幕下方的跑馬燈呈現某市遭敵軍攻擊、某港爆炸，還有規模七的地震等訊息，讓 許多觀眾見到這些「獨家新聞」大驚失色，該電視台立即更正說明是「誤植」，並且向公眾道歉。在野黨 則舉行記者會強烈質疑該電視台失職，要求嚴正查辦，甚至將該電視台撤照，其董事長、總經理也必須為 此失誤下台負責。下列那一項解讀可能為此事件的最適切說明？', '["報導符合媒體在「設定議題、促進討論」的公共角色", "此為「媒體再現」的結果，與社會事實可能有所出入", "重要訊息在產製過程中，新聞守門人未善盡把關職責", "報導內容誇大不實誤導大眾，使閱聽者陷入總白癡化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00012', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '承上題，在野黨舉行記者會譴責該公營電視台失職以及懲處高層人員的作法，是希望相關人員為此負起何 項責任？', '["行政責任", "刑事責任", "民事責任", "道德責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00013', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '我國政府在外交政策上致力於和平與發展，建立與邦交國永續夥伴關係，並與友好國家深化與廣化多元領 域的實質關係，持續爭取國際參與及對國際社會作出貢獻，發揮軟實力並透過國際合作及人道救援等方 式，提升臺灣的國際形象。由上述可知，我國致力於以何種方式參與國際事務？', '["官方交流", "踏實外交", "共同防禦", "宣示主權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00014', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '電影「老鷹想飛」記錄了臺灣田間傳統農法使用落葉劑以快速採收紅豆，卻造成很多禽鳥誤食中毒，老鷹又 吃這些中毒的禽鳥也因而死亡，本片喚醒了許多民眾對於土壤生態的意識。以上所述屬於經濟學的何種現象？', '["機會成本", "外部成本", "政府失靈", "外顯成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
